-- SagaTrail WordPress SQL | 1296 Routen | 2026-07-18
SET NAMES utf8mb4;
SET time_zone = '+00:00';

DROP TABLE IF EXISTS `sagatrail_routen`;
CREATE TABLE `sagatrail_routen` (
  `id`                  VARCHAR(60)    NOT NULL,
  `name`                VARCHAR(255)   NOT NULL,
  `kanton`              VARCHAR(60)    NOT NULL,
  `distanz_km`          DECIMAL(6,2)   DEFAULT NULL,
  `aufstieg_m`          SMALLINT       DEFAULT NULL,
  `minuten`             SMALLINT       DEFAULT NULL,
  `sac`                 VARCHAR(10)    DEFAULT NULL,
  `lat`                 DECIMAL(10,7)  NOT NULL,
  `lng`                 DECIMAL(10,7)  NOT NULL,
  `featured`            TINYINT(1)     NOT NULL DEFAULT 0,
  `photo_url`           TEXT           DEFAULT NULL,
  `photo_attribution`   VARCHAR(500)   DEFAULT NULL,
  PRIMARY KEY (`id`),
  INDEX `idx_kanton` (`kanton`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



























DROP TABLE IF EXISTS `sagatrail_partner_leads`;
CREATE TABLE `sagatrail_partner_leads` (
  `id`           INT            NOT NULL AUTO_INCREMENT,
  `route_id`     VARCHAR(60)    NOT NULL,
  `route_name`   VARCHAR(255)   NOT NULL,
  `kanton`       VARCHAR(60)    NOT NULL,
  `osm_id`       VARCHAR(40)    NOT NULL,
  `typ`          VARCHAR(30)    NOT NULL,
  `name`         VARCHAR(255)   NOT NULL,
  `adresse`      VARCHAR(500)   DEFAULT NULL,
  `telefon`      VARCHAR(50)    DEFAULT NULL,
  `website`      VARCHAR(500)   DEFAULT NULL,
  `email`        VARCHAR(255)   DEFAULT NULL,
  `tier`         ENUM('Top','Mid','Low') DEFAULT NULL,
  `lat`          DECIMAL(10,7)  DEFAULT NULL,
  `lng`          DECIMAL(10,7)  DEFAULT NULL,
  `erstellt_am`  DATETIME       NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_osm` (`osm_id`),
  INDEX `idx_route` (`route_id`),
  INDEX `idx_kanton` (`kanton`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `sagatrail_osm_progress`;
CREATE TABLE `sagatrail_osm_progress` (
  `route_id`     VARCHAR(60)    NOT NULL,
  `abgefragt_am` DATETIME       NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `anzahl_leads` SMALLINT       NOT NULL DEFAULT 0,
  PRIMARY KEY (`route_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
